\documentclass[letterpaper,10pt]{article}
\usepackage{latexsym}
\usepackage[empty]{fullpage}
\usepackage{titlesec}
\usepackage{enumitem}
\usepackage[hidelinks]{hyperref}
\usepackage{fancyhdr}
\usepackage[english]{babel}
\usepackage{tabularx}
\usepackage{fontawesome5}
\pagestyle{fancy}
\fancyhf{}
\renewcommand{\headrulewidth}{0pt}
\renewcommand{\footrulewidth}{0pt}

\usepackage[margin=0.2in]{geometry}
\usepackage{microtype}
\usepackage{titlesec}
\usepackage{enumitem}

\setlength{\parindent}{0pt}
\setlength{\parskip}{0pt}
\raggedbottom
\linespread{0.99}

\titlespacing*{\section}{0pt}{4pt}{3pt}
\titleformat{\section}
{\scshape\large\bfseries}
{}{0pt}{}
[\vspace{-2pt}\titlerule\vspace{3pt}]

\setlist[itemize]{
  leftmargin=*,
  itemsep=2pt,
  topsep=4pt,
  parsep=0pt,
  partopsep=0pt
}

\newcommand{\resumeItem}[1]{\item\small{#1}}
\newcommand{\resumeSubheading}[3]{%
  \vspace{2pt}\item
  \begin{tabular*}{\textwidth}{l@{\extracolsep{\fill}}r}
    \textbf{#1} & \textbf{\small #2} \\
    \textit{\small #3} \\
  \end{tabular*}\vspace{-2pt}
}
\newcommand{\resumeSubHeadingListStart}{\begin{itemize}[leftmargin=0in, label={}]}
\newcommand{\resumeSubHeadingListEnd}{\end{itemize}}
\newcommand{\resumeItemListStart}{\begin{itemize}[leftmargin=0.15in, itemsep=2pt, topsep=4pt]}
\newcommand{\resumeItemListEnd}{\end{itemize}}

\begin{document}

% ---------- Header ----------
\begin{center}
    {\Huge \scshape Shrey Bishnoi} \\ \vspace{4pt}
    \faPhone\ +1 (623) 498-7996 \quad
    \faEnvelope\ sbishno2@asu.edu
\end{center}

% ---------- Summary ----------
\section{Summary}
Graduate Computer Science student with experience supporting \textbf{administrative, instructional, and data-driven operations} in academic and professional settings. Proven ability to manage schedules, maintain accurate records, prepare reports, and communicate clearly with students, faculty, and stakeholders. Reliable, detail-oriented, and comfortable handling confidential information while supporting day-to-day office and research operations.

% ---------- Education ----------
\section{Education}
\resumeSubHeadingListStart

\resumeSubheading
{Arizona State University}{Aug 2025 -- May 2027}
{Master of Science in Computer Science (CGPA: 4.11)}
\resumeItemListStart
\resumeItem{Coursework: Data Processing at Scale, Database Systems, Algorithms, Knowledge Representation}
\resumeItemListEnd

\resumeSubheading
{Maharaja Agrasen Institute of Technology}{Aug 2019 -- Jul 2023}
{Bachelor of Science in Computer Science (CGPA: 3.7)}
\resumeItemListStart
\resumeItem{Coursework: Data Structures \& Algorithms, DBMS, Operating Systems, Computer Networks}
\resumeItemListEnd

\resumeSubHeadingListEnd

% ---------- Experience ----------
\section{Experience}
\resumeSubHeadingListStart

\resumeSubheading
{ZS Associates}{Sep 2023 -- Jun 2025}
{Software Engineer}
\resumeItemListStart
\resumeItem{Owned \textbf{backend services} in \textbf{Python, Node.js, and PostgreSQL} supporting analytics workflows for product and data teams.}
\resumeItem{Optimized \textbf{data-intensive REST APIs}, reducing report latency by \textbf{~40\%} through query tuning, indexing, and service refactors.}
\resumeItem{Built internal \textbf{React dashboards} to monitor system health, data freshness, and key business metrics.}
\resumeItem{Automated \textbf{ETL pipelines} in Python and SQL, cutting manual analyst effort by \textbf{~40\%}.}
\resumeItem{Improved reliability via log-based debugging, targeted tests, and \textbf{Dockerized deployments} with CI/CD.}
\resumeItemListEnd

\resumeSubheading
{Coding Ninjas}{Jun 2022 -- Sep 2022}
{Teaching Assistant}
\resumeItemListStart
\resumeItem{Assisted instructors in delivering C++ and Data Structures content to 200+ students through live sessions and forums.}
\resumeItem{Provided one-on-one academic support, clarified assignments, and resolved student queries promptly.}
\resumeItem{Reviewed and evaluated assignments while maintaining grading accuracy and clear feedback.}
\resumeItemListEnd

\resumeSubheading
{Dreadnought School}{Jun 2022 -- Aug 2022}
{Software Engineer}
\resumeItemListStart
\resumeItem{Applied \textbf{OOP principles and data structures} to implement backend features in a client--server architecture.}
\resumeItem{Designed and consumed \textbf{HTTP/REST APIs}, developing a strong understanding of request lifecycles and error handling.}
\resumeItem{Worked with \textbf{PostgreSQL/MySQL} to design schemas, write optimized queries, and maintain data integrity.}
\resumeItem{Developed responsive \textbf{UI components} using modern JavaScript frameworks (Vue.js-style patterns).}
\resumeItem{Used \textbf{Git} for version control and gained exposure to \textbf{CI/CD}, cloud deployments, and Agile workflows.}
\resumeItemListEnd


\resumeSubheading
{Wave Society}{Oct 2019 -- Oct 2020}
{Research Aide}
\resumeItemListStart
\resumeItem{Collected participation data, session feedback, and attendance metrics for wellness research initiatives.}
\resumeItem{Maintained organized records and prepared summary reports for internal review and planning.}
\resumeItem{Assisted with logistics and coordination for ongoing student-focused programs.}
\resumeItemListEnd

\resumeSubheading
{The Education Tree}{Sep 2019 -- Feb 2020}
{Office Aide}
\resumeItemListStart
\resumeItem{Assisted with front-desk operations including scheduling, record maintenance, and event coordination.}
\resumeItem{Managed student sign-ups, attendance tracking, and shared calendars using Google Workspace.}
\resumeItem{Drafted emails and updates regarding programs, schedules, and events.}
\resumeItemListEnd

\resumeSubHeadingListEnd

% ---------- Skills ----------
\section{Skills}
\textbf{Administrative \& Office:} Scheduling, Calendar Management, Record Keeping, Documentation, Front Desk Support, Customer Service, Confidentiality \\
\textbf{Software \& Tools:} Microsoft Office (Word, Excel, PowerPoint, Outlook), Google Workspace (Docs, Sheets, Slides, Calendar) \\
\textbf{Data \& Reporting:} Data entry, Excel-based reporting, Dashboard interpretation, Accuracy validation \\
\textbf{Technical:} Python, SQL, C++, JavaScript, Git, REST APIs \\
\textbf{Core Strengths:} Organization, Attention to Detail, Multitasking, Time Management, Clear Communication

\end{document}

